class ContentLengthLimitMiddleware(BaseHTTPMiddleware):
    """
    Rejects clearly oversized uploads before the application starts parsing the
    multipart body. This avoids wasting CPU/disk on requests that advertise a
    body larger than our limit.
    """

    async def dispatch(self, request: Request, call_next):
        if request.url.path == "/api/upload" and request.method == "POST":
            content_length = request.headers.get("content-length")
            if content_length:
                try:
                    # Multipart overhead means the full request body may be
                    # slightly larger than the file itself, so allow some room.
                    if int(content_length) > MAX_FILE_SIZE + 1024 * 1024:
                        return JSONResponse(
                            status_code=HTTP_413_REQUEST_ENTITY_TOO_LARGE,
                            content={
                                "ok": False,
                                "error": {
                                    "code": "request_too_large",
                                    "message": "Upload request is too large.",
                                },
                            },
                        )
                except ValueError:
                    return JSONResponse(
                        status_code=HTTP_400_BAD_REQUEST,
                        content={
                            "ok": False,
                            "error": {
                                "code": "invalid_content_length",
                                "message": "Invalid Content-Length header.",
                            },
                        },
                    )

        return await call_next(request)


app.add_middleware(ContentLengthLimitMiddleware)


def sanitize_filename(filename: Optional[str]) -> str:
    """
    Removes path traversal, control characters, dangerous shell characters,
    repeated separators, and overly long names.
    """
    if not filename:
        return "upload"

    name = Path(filename).name
    name = name.replace("\x00", "")
    name = re.sub(r"[\r\n\t]", "_", name)
    name = re.sub(r"[^A-Za-z0-9._-]", "_", name)
    name = re.sub(r"_+", "_", name).strip("._- ")

    if not name:
        name = "upload"

    stem = Path(name).stem[:MAX_FILENAME_LENGTH]
    return stem or "upload"


def detect_image_mime(header: bytes) -> Optional[str]:
    """
    Validates by magic bytes, not by extension or Content-Type.

    WebP requires:
    - RIFF at bytes 0..3
    - WEBP at bytes 8..11
    """
    if header.startswith(b"\xff\xd8\xff"):
        return "image/jpeg"

    if header.startswith(b"\x89PNG\r\n\x1a\n"):
        return "image/png"

    if header.startswith((b"GIF87a", b"GIF89a")):
        return "image/gif"

    if len(header) >= 12 and header[:4] == b"RIFF" and header[8:12] == b"WEBP":
        return "image/webp"

    return None


def ensure_upload_dir() -> None:
    try:
        UPLOAD_DIR.mkdir(mode=0o750, parents=True, exist_ok=True)
    except PermissionError:
        raise UploadError(HTTP_500_INTERNAL_SERVER_ERROR, "storage_permission_denied", "Upload storage is not writable.")
    except OSError:
        raise UploadError(HTTP_500_INTERNAL_SERVER_ERROR, "storage_unavailable", "Upload storage is unavailable.")

    if not UPLOAD_DIR.is_dir():
        raise UploadError(HTTP_500_INTERNAL_SERVER_ERROR, "storage_invalid", "Upload path is not a directory.")


def has_enough_disk_space(required_bytes: int) -> bool:
    try:
        usage = shutil.disk_usage(UPLOAD_DIR)
        # Reserve extra headroom for filesystem metadata and concurrent writes.
        return usage.free >= required_bytes + 2 * 1024 * 1024
    except OSError:
        return False


@app.post("/api/upload", status_code=HTTP_201_CREATED)
async def upload_image(request: Request, file: UploadFile = File(...)):
    attempt_id = uuid.uuid4().hex
    client_ip = request.client.host if request.client else "unknown"
    original_filename = file.filename or ""

    logger.info(
        "upload_attempt attempt_id=%s client_ip=%s filename=%r content_type=%r",
        attempt_id,
        client_ip,
        original_filename,
        file.content_type,
    )

    temp_path: Optional[Path] = None

    try:
        ensure_upload_dir()

        if not original_filename:
            raise UploadError(HTTP_400_BAD_REQUEST, "missing_filename", "No filename was provided.")

        safe_stem = sanitize_filename(original_filename)

        # Read only a small header first. This validates empty files, truncated
        # files, and spoofed Content-Type/extensions without loading the body.
        header = await file.read(64)
        if not header:
            raise UploadError(HTTP_400_BAD_REQUEST, "empty_file", "Uploaded file is empty.")

        detected_mime = detect_image_mime(header)
        if detected_mime not in EXTENSIONS:
            raise UploadError(
                HTTP_415_UNSUPPORTED_MEDIA_TYPE,
                "unsupported_file_type",
                "Only JPEG, PNG, GIF, and WebP images are allowed.",
            )

        # Reject obvious Content-Type spoofing when a header was supplied.
        if file.content_type and file.content_type != detected_mime:
            raise UploadError(
                HTTP_415_UNSUPPORTED_MEDIA_TYPE,
                "mime_type_mismatch",
                "File content does not match the declared MIME type.",
            )

        if not has_enough_disk_space(MAX_FILE_SIZE):
            raise UploadError(
                HTTP_500_INTERNAL_SERVER_ERROR,
                "insufficient_storage",
                "Server does not have enough free space for this upload.",
            )

        final_name = f"{safe_stem}-{uuid.uuid4().hex}{EXTENSIONS[detected_mime]}"
        final_path = (UPLOAD_DIR / final_name).resolve()

        # Prevent path traversal even after sanitization.
        if UPLOAD_DIR not in final_path.parents:
            raise UploadError(HTTP_400_BAD_REQUEST, "invalid_filename", "Invalid filename.")

        sha256 = hashlib.sha256()
        bytes_written = 0

        fd, raw_temp_path = tempfile.mkstemp(
            prefix=f".{final_name}.",
            suffix=".tmp",
            dir=str(UPLOAD_DIR),
        )
        temp_path = Path(raw_temp_path)

        try:
            with os.fdopen(fd, "wb") as out:
                # Write the validated header first because we already consumed it.
                out.write(header)
                sha256.update(header)
                bytes_written += len(header)

                if bytes_written > MAX_FILE_SIZE:
                    raise UploadError(
                        HTTP_413_REQUEST_ENTITY_TOO_LARGE,
                        "file_too_large",
                        "Uploaded file exceeds the 10MB limit.",
                    )

                while True:
                    chunk = await file.read(CHUNK_SIZE)
                    if not chunk:
                        break

                    bytes_written += len(chunk)
                    if bytes_written > MAX_FILE_SIZE:
                        raise UploadError(
                            HTTP_413_REQUEST_ENTITY_TOO_LARGE,
                            "file_too_large",
                            "Uploaded file exceeds the 10MB limit.",
                        )

                    try:
                        out.write(chunk)
                    except OSError as e:
                        if e.errno == errno.ENOSPC:
                            raise UploadError(
                                HTTP_500_INTERNAL_SERVER_ERROR,
                                "disk_full",
                                "Server ran out of disk space while saving the upload.",
                            )
                        raise

                    sha256.update(chunk)

                try:
                    out.flush()
                    os.fsync(out.fileno())
                except OSError:
                    raise UploadError(
                        HTTP_500_INTERNAL_SERVER_ERROR,
                        "fsync_failed",
                        "Upload could not be safely committed to disk.",
                    )

            # Atomic commit. The file is either absent or fully present.
            try:
                os.replace(temp_path, final_path)
                temp_path = None
            except PermissionError:
                raise UploadError(
                    HTTP_500_INTERNAL_SERVER_ERROR,
                    "storage_permission_denied",
                    "Upload storage is not writable.",
                )
            except OSError:
                raise UploadError(
                    HTTP_500_INTERNAL_SERVER_ERROR,
                    "atomic_rename_failed",
                    "Upload could not be finalized.",
                )

        except Exception:
            if temp_path and temp_path.exists():
                try:
                    temp_path.unlink()
                except OSError:
                    logger.warning("failed_to_remove_temp_file attempt_id=%s temp_path=%s", attempt_id, temp_path)
            raise

        logger.info(
            "upload_success attempt_id=%s filename=%s bytes=%d mime=%s sha256=%s",
            attempt_id,
            final_name,
            bytes_written,
            detected_mime,
            sha256.hexdigest(),
        )

        return JSONResponse(
            status_code=HTTP_201_CREATED,
            content={
                "ok": True,
                "file": {
                    "id": final_path.stem,
                    "filename": final_name,
                    "size": bytes_written,
                    "mime_type": detected_mime,
                    "sha256": sha256.hexdigest(),
                },
            },
        )

    except UploadError as e:
        logger.warning(
            "upload_failure attempt_id=%s code=%s status=%d filename=%r",
            attempt_id,
            e.code,
            e.status_code,
            original_filename,
        )
        raise

    except Exception:
        logger.exception("upload_failure attempt_id=%s code=unexpected_error filename=%r", attempt_id, original_filename)
        raise UploadError(
            HTTP_500_INTERNAL_SERVER_ERROR,
            "unexpected_error",
            "Upload failed due to an internal server error.",
        )

    finally:
        try:
            await file.close()
        except Exception:
            logger.warning("failed_to_close_upload_file attempt_id=%s", attempt_id)
